/* 作者：墨千尾（dc：@inkfoxxxx） */
/* 二改随意不用问我，欢迎到原贴分享😋，二传请标明来源。代码比较史山，不懂的尽量别乱动，问AI问AI问AI！ */
/* 输入框文字可自定义，有✒️emoji标志。其他所有有红心emoji💗标注的地方都可自改 */

/* ---字体--- */
/* 引入全局字体 */
@import url("https://fontsapi.zeoseven.com/437/main/result.css");
/* 引入斜体/星号字体 */
@import url("https://fontsapi.zeoseven.com/440/main/result.css");

/* 全局应用主要字体 */
body {
    font-family: "Huiwen-MinchoGBK", "Source Han Serif SC", serif;
    font-weight: normal;
}

/* 斜体（*包裹内容*）应用次要字体 */
.mes_text em, .mes_text i {
    font-family: "Huiwen-Fangsong", "STKaiti", "KaiTi", serif;
    font-weight: normal;
    font-style: normal; /* 覆盖默认的斜体样式，因为字体本身就是手写/仿宋风格 */
    color: var(--SmartThemeEmColor);
}

/* 引号（“包裹内容”）的边框装饰 */
.mes_text blockquote, .mes_text q {
    display: inline-block;
    position: relative;
    background-image: url('https://files.catbox.moe/62pe1x.png');
    background-size: 100% 100%;
    background-repeat: no-repeat;
    padding: 0.5em 1.5em; /* 为边框图片留出空间 */
    margin: 0.2em 0;
    border: none;
    color: inherit; /* 继承父元素的颜色 */
    background-color: transparent; /* 清除默认背景 */
}

/* 移除blockquote的默认边框和边距 */
blockquote {
    border-left: none;
    margin-inline-start: 0;
    margin-inline-end: 0;
}


/* ---顶栏--- */
/* 导航栏背景 */
#top-settings-holder {
    background-image: url('https://files.catbox.moe/rbmzvx.png');
    background-size: 100% 100%;
    background-position: center;
    background-color: #F0EBE5; /* 背景底色 */
    box-shadow: none;
    border-bottom: 2px solid #C9A86A; /* 祥云金边框 */
}

/* 隐藏原有的FontAwesome图标 */
.drawer-icon.fa-fw::before {
    content: '' !important;
    font-size: 0 !important;
}

/* 统一设置图标样式 */
.drawer-icon.fa-fw {
    width: 40px; /* 调整图标宽度 */
    height: 40px; /* 调整图标高度 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    transition: transform 0.3s ease;
}

.drawer-icon.fa-fw:hover {
    transform: scale(1.1);
}

/* 依次替换导航栏图标 */
#ai-config-button .drawer-icon { background-image: url('https://files.catbox.moe/hs1qiu.png'); }
#sys-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/f2svhn.png'); }
#advanced-formatting-button .drawer-icon { background-image: url('https://files.catbox.moe/hs1qiu.png'); }
#WI-SP-button .drawer-icon { background-image: url('https://files.catbox.moe/f2svhn.png'); }
#user-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/hs1qiu.png'); }
#logo_block .drawer-icon { background-image: url('https://files.catbox.moe/f2svhn.png'); }
#extensions-settings-button .drawer-icon { background-image: url('https://files.catbox.moe/hs1qiu.png'); }
#table_database_settings_drawer .drawer-icon { background-image: url('https://files.catbox.moe/motesx.png'); }
#persona-management-button .drawer-icon { background-image: url('https://files.catbox.moe/f2svhn.png'); }
#rightNavHolder .drawer-icon { background-image: url('https://files.catbox.moe/hs1qiu.png'); }

/* 展开盒子时，图标变化（柔和过渡） */
.drawer-icon.fa-fw {
    position: relative; /* 让图标成为伪元素的定位参考 */
}

/* 这个::before伪元素是我们的“活动状态”图标层 */
.drawer-icon.fa-fw::before {
    content: ''; /* 伪元素必须有content属性 */
    position: absolute; /* 覆盖在原图标上 */
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: url('https://files.catbox.moe/jtdyi8.png'); /* 这是“展开时”的图标 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    opacity: 0; /* 默认状态下完全透明 */
    transition: opacity 0.3s ease-in-out; /* 这是实现柔和效果的关键 */
    pointer-events: none; /* 重要！让点击事件可以穿透这个覆盖层，点击到下面的原始图标 */
}

/* 
 * 当图标没有 .closedIcon 这个class时，说明抽屉是打开的。
 * 这比 :focus-within 更准确，因为它直接反映了SillyTavern的JS所设置的状态。
 */
.drawer-icon:not(.closedIcon)::before {
    opacity: 1; /* 让伪元素（展开图标）变得不透明 */
}


/* ---底栏--- */

/* 1. 隐藏所有原始图标的::before伪元素和内部的<i>元素 */
#options_button::before,
#extensionsMenuButton::before,
#send_but::before,
#quick-reply-rocket-button > i { /* 精确指向内部的<i>图标 */
    display: none !important;
}

/* 2. 统一设置所有图标按钮的样式 */
#options_button,
#extensionsMenuButton,
#send_but,
#quick-reply-rocket-button {
    width: 32px;
    height: 32px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    transition: transform 0.2s ease;
    font-size: 0; /* 隐藏可能存在的文本 */
    border: none; /* 清除可能存在的边框 */
    background-color: transparent; /* 清除可能存在的背景色 */
}

#options_button:hover,
#extensionsMenuButton:hover,
#send_but:hover,
#quick-reply-rocket-button:hover {
    transform: scale(1.1);
}

/* 3. 分别设置每个按钮的背景图片 */
#options_button { background-image: url('https://files.catbox.moe/b8jj44.png'); }
#extensionsMenuButton { background-image: url('https://files.catbox.moe/en8bb8.png'); }
#send_but { background-image: url('https://files.catbox.moe/391iuw.png'); }
#quick-reply-rocket-button { background-image: url('https://files.catbox.moe/plpils.png'); }

/* ---消息框--- */
/* 基础消息框样式 */
.mes {
    position: relative; 
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    margin-bottom: 20px;
    padding-top: 40px; 
    overflow: visible !important; /* 关键！允许子元素（装饰图）溢出显示 */
}

/* 消息框右上角操作按钮 - 关键修复：提升层级使其可点击 */
.mes_buttons {
    position: relative; /* 激活z-index */
    z-index: 99; /* 赋予一个非常高的层级，确保它在最顶层 */
    pointer-events: auto; /* 确保自身和子元素可以接收鼠标事件 */
}

/* 同时确保按钮本身也能接收事件 */
.mes_buttons .mes_button {
    pointer-events: auto;
}
.mes_edit_buttons {
    position: relative; /* 激活z-index */
    z-index: 100; /* 设置一个比.mes_buttons更高的层级 */
}

/* 消息内容块，应用边框图片 */
.mes_block {
    position: relative; /* 为装饰贴图定位 */
    padding: 45px 2em 2em 2em; /* 关键！增大顶部内边距，把文字内容向下推，避免被头像遮挡 */
    border: 40px solid transparent; /* 创建一个透明的边框区域以应用border-image */
    width: 100%;
    margin-top: 0; /* 移除之前不精确的负外边距 */
}


/* 消息框装饰贴图 */
/* 如果挡字了可以按照下面的注释自行修改，不喜欢的话可以替换链接的图，或者把这一块注释掉/删掉 */
.mes_block::before, .mes_block::after {
    content: '';
    position: absolute;
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 0;
}

/* AI消息框 - 左上角装饰 */
.mes[is_user="false"] .mes_block::before {
    background-image: url('https://files.catbox.moe/n6gylk.png');
    width: 110px;  /* 💗装饰图大小💗 */
    height: 110px; /* 💗装饰图大小 */
    top: -20px;/* 💗装饰图距离上方的大小，绝对值越大越往上，下面的left同理💗 */
    left: -20px;
}

/* AI消息框 - 右下角装饰 */
.mes[is_user="false"] .mes_block::after {
    background-image: url('https://files.catbox.moe/nyjq3s.png');
    width: 200px;  /* 💗装饰图大小💗 */
    height: 200px; /* 💗装饰图大小💗 */
    bottom: -10px;/* 💗这里的修改原理同上💗 */
    right: -75px;
}

/* User消息框 - 右下角装饰 */
.mes[is_user="true"] .mes_block::after {
    background-image: url('https://files.catbox.moe/jzxlm6.png');
    width: 150px;  /* 💗装饰图大小💗 */
    height: 100px; /* 💗装饰图大小💗 */
    bottom: -5px;/* 💗这里的修改原理同上💗 */
    right: -40px;
}

/* 确保消息文本在边框内 */
.mes_text {
    background: rgba(255, 255, 255, 0.5); /* 给文字一个半透明的底色以提高可读性 */
    padding: 10px;
    border-radius: 5px;
}



/* ---头像与名字--- */
/* 头像和名字的容器，使其显示在消息框上方 */
.mesAvatarWrapper {
    position: absolute; /* 关键！让头像脱离文档流，可以自由移动 */
    top: 0; /* 定位到父容器(.mes)的顶部 */
    left: 50%; /* 水平居中第一步 */
    transform: translateX(-50%); /* 水平居中第二步（精确居中） */
    z-index: 5; /* 确保头像在消息框上方 */
    width: 100%; /* 让其宽度与父容器一致，便于内部居中 */
    display: flex; /* 保持其内部元素（如名字）的flex布局 */
    flex-direction: column;
    align-items: center;
}
/* 角色名称 */
.mes .ch_name {
    background-color: #F0EBE5;
    padding: 2px 15px;
    border-radius: 15px;
    border: 1px solid #C9A86A;
    color: #3A3A3A;
    margin-top: 10px;
}

/* 头像容器 */
/* ---头像与名字--- */

/* 头像容器 - 确保正方形 */
/* 头像容器 - 确保正方形并有明确尺寸 */
.avatar {
    position: relative;
    width: 60px; /* 为桌面端设置一个基础宽度 */
    height: 60px; /* 关键！明确设置高度，防止坍缩 */
    aspect-ratio: 1 / 1; /* 保留此项，作为双重保险 */
    flex-shrink: 0; /* 在flex布局中，防止头像被压缩 */
}

/* 头像图片本身 - 确保正圆 */
.avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover; /* 保证图片不变形地填满容器 */
    border-radius: 50%; /* 将正方形的图片切成完美的圆形 */
}

/* 头像框伪元素 - 确保与头像完美贴合 */
.avatar::after {
    content: '';
    position: absolute;
}

/* AI头像框 */
.mes[is_user="false"] .avatar::after {
    background-image: url('https://files.catbox.moe/qe93er.png');
 /* 使用百分比和transform使其完美居中并随头像缩放 */
    top: 60%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 160%; /* 根据框图和头像的比例微调，让框看起来大小合适 */
    height: 140%;
    background-size: contain;
    background-repeat: no-repeat;
    pointer-events: none; 
}

/* User头像框 */
.mes[is_user="true"] .avatar::after {
    background-image: url('https://files.catbox.moe/jzy02z.png');
 /* 使用百分比和transform使其完美居中并随头像缩放 */
    top: 55%;
    left: 63%;
    transform: translate(-50%, -50%);
    width: 155%; /* 根据框图和头像的比例微调，让框看起来大小合适 */
    height: 135%;
    background-size: contain;
    background-repeat: no-repeat;
    pointer-events: none; 
}

/* 滑动条优化 */
/* 默认状态下，让滚动条轨道和滑块都透明 */
#chat::-webkit-scrollbar,
#chat::-webkit-scrollbar-track,
#chat::-webkit-scrollbar-thumb {
    background-color: transparent;
    width: 8px; /* 可以设置一个合适的宽度 */
}

/* 当鼠标悬停在聊天区或滚动条上时，才让滚动条滑块显示出来 */
#chat:hover::-webkit-scrollbar-thumb,
#chat::-webkit-scrollbar-thumb:hover {
    background-color: rgba(201, 168, 106, 0.5); /* 使用半透明的祥云金色 */
    border-radius: 4px; /* 给滑块一个圆角 */
}

/* ---代码块与预格式化文本样式--- */

/* 1. 为 <code> 标签添加画轴背景图 */
.mes_text code {
    display: inline-block; /* 确保背景和内边距正确应用 */
    background-image: url('https://files.catbox.moe/rbmzvx.png');
    background-size: 100% 100%; /* 让背景图完整填充整个元素区域 */
    background-repeat: no-repeat;
    background-position: center;

    /* 关键：使用内边距(padding)把文字“挤”到背景图的中间区域，模拟出边框效果 */
    padding: 1.2em 2.5em; 

    color: #554A42; /* 设置古典的深棕色字体 */
    margin: 5px 0;

    /* 清除可能继承的旧样式 */
    border: none;
    background-color: transparent;
}

/* 2. 为 <pre> 标签添加底部背景图 */
.mes_text pre {
    background-color: rgba(249, 245, 242, 0.85); /* 设置一个与主题协调的背景色 */
    background-image: url('https://files.catbox.moe/ot1g08.png');
    background-repeat: no-repeat;
    background-position: bottom center; /* 关键！将背景图定位在容器的底部中央 */
    background-size: 100% auto; /* 让背景图宽度100%填充，高度自动缩放 */
    border: 1px solid #E0D8D0; /* 添加一个细微的边框 */
    border-radius: 8px; /* 添加圆角 */
    padding: 1em; /* 增加内边距 */
    padding-bottom: 80px; /* 关键！在底部留出足够的空间来完整显示背景图 */
    margin: 10px 0; /* 与其他内容保持间距 */
    overflow-x: auto; /* 如果代码过长，允许水平滚动 */
}

/* 3. <pre> 标签内的 <code> 标签样式重置 */
/* 当<code>在<pre>内部时，我们不希望它有画轴边框，只需继承<pre>的样式即可 */
.mes_text pre code {
    background: transparent;
    border: none;
    border-image: none;
    padding: 0;
    color: inherit;
    display: inline; /* 恢复为普通行内元素 */
    margin: 0;
}

/* ---自定义输入框样式与占位符 (最终父容器定位版)--- */

/* 1. 为输入框本身设置自定义字体 */
#send_textarea {
    font-family: "Huiwen-MinchoGBK", "Source Han Serif SC", serif !important;
    font-weight: normal !important;
}

/* 2. 把原始的 placeholder 文字变透明，让它“消失”在视野中 */
#send_textarea::placeholder {
    color: transparent !important;
}

/* 3. 对输入框的父容器进行相对定位，为伪元素做准备 */
#nonQRFormItems {
    position: relative;
}

/* 4. 在父容器上创建伪元素，用来显示我们的自定义文字 */
/* :has() 是一个现代CSS选择器，它的意思是“当 #nonQRFormItems 内部包含一个正在显示占位符的 #send_textarea 时” */
#nonQRFormItems:has(#send_textarea:placeholder-shown)::after {
    content: "江山姓氏改写，不过史书一页。"; /* ✒️✒️在这里输入想要的自定义文字✒️✒️ */

    /* 以下是样式和定位 */
    position: absolute;
    top: 50%;
    /* 关键定位：从左边开始，留出左侧图标的宽度，再加上一点边距 */
    left: 100px; /* 💗在这里修改自定义文字和左侧导航图标的距离💗 */
    transform: translateY(-40%);

    color: rgba(58, 58, 58, 0.6); /* 设置一个比主文字稍淡的颜色 */
    pointer-events: none; /* 确保这个伪元素不会影响您点击输入框 */
    white-space: nowrap; /* 防止文字换行 */

    /* 继承输入框的字体 */
    font-family: "Huiwen-MinchoGBK", "Source Han Serif SC", serif;
    font-weight: normal;
    font-size: 1rem; /* 💗在这里根据需要调整字体大小，1rem通常与默认大小一致。想更小就往1以下改，更大就往1以上改💗 */
}
